# Unit Tests for clamp() Function

```python
import pytest
from typing import Union


def clamp(value: float, min_val: float, max_val: float) -> float:
    return max(min_val, min(value, max_val))


class TestClampHappyPath:
    """Tests for normal, expected usage of clamp()"""

    def test_clamp_value_within_range(self):
        """Value is between min and max"""
        assert clamp(5.0, 0.0, 10.0) == 5.0

    def test_clamp_value_at_min_boundary(self):
        """Value equals min_val"""
        assert clamp(0.0, 0.0, 10.0) == 0.0

    def test_clamp_value_at_max_boundary(self):
        """Value equals max_val"""
        assert clamp(10.0, 0.0, 10.0) == 10.0

    def test_clamp_value_below_min(self):
        """Value is below min_val, should return min_val"""
        assert clamp(-5.0, 0.0, 10.0) == 0.0

    def test_clamp_value_above_max(self):
        """Value is above max_val, should return max_val"""
        assert clamp(15.0, 0.0, 10.0) == 10.0

    def test_clamp_with_negative_range(self):
        """Range includes negative numbers"""
        assert clamp(-5.0, -10.0, -1.0) == -5.0

    def test_clamp_with_negative_value_below_range(self):
        """Negative value below negative range"""
        assert clamp(-15.0, -10.0, -1.0) == -10.0

    def test_clamp_with_negative_value_above_range(self):
        """Negative value above negative range"""
        assert clamp(-0.5, -10.0, -1.0) == -1.0


